  ('police-3218f787-moex-00280', 'police-3218f787', 'police-3218f787-moex-110-15a7b19c', 'sub-police-3218f787-01', NULL, 'single_choice', '關於考試院之職權，下列敘述何者錯誤？', '["公務人員之任用資格，應經考試院依法考選銓定之", "考試院職權之行使限制人民權利者，須有法律之依據，始得為之", "考試院就其所掌事項之法律案，有對立法院提案之權", "考試院對立法院通過之法律案，得經總統核可，移請立法院覆議"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:10+00:00", "source_pdf_sha1": "1390dfe43c09", "answer_pdf_sha1": "b5e0a630e6f1", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "505", "s": "0206", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中華民國憲法與警察專業英文", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "犯罪防治人員預防組"}'::jsonb, NULL),
  ('police-3218f787-moex-00281', 'police-3218f787', 'police-3218f787-moex-110-15a7b19c', 'sub-police-3218f787-01', NULL, 'single_choice', '依司法院大法官解釋之意旨，關於立法院文件調閱權，下列敘述何者錯誤？', '["立法院使用調閱權所取得之資訊，於使用時應注意維護關係人之名譽隱私及營業秘密", "立法院不得調閱檢察機關偵查中之案件卷證", "立法院得調閱已偵查終結之所有案件之卷證", "立法院得立法對拒絕配合文件調閱者科處罰鍰"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:10+00:00", "source_pdf_sha1": "1390dfe43c09", "answer_pdf_sha1": "b5e0a630e6f1", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "505", "s": "0206", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中華民國憲法與警察專業英文", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "犯罪防治人員預防組"}'::jsonb, NULL),
